List<PartModel> getPartsByEra(String era) =>
    PARTS.where((p) => p.era == era).toList();

List<Map<String, dynamic>> getEraGroups() {
  return ERAS.map((era) {
    return {
      'era': era,
      'parts': getPartsByEra(era.id),
    };
  }).where((g) => (g['parts'] as List).isNotEmpty).toList();
}
